import React, { useEffect, useState, useMemo } from "react";
import { getIncome, addIncome, logoutUser } from "../api/api";
import IncomeForm from "../components/IncomeForm";
import DashboardCard from "../components/DashboardCard";
import IncomeChart from "../components/IncomeChart";

/* =========================
   Dashboard Component
========================= */
export default function Dashboard({ onLogout }) {
  const [incomeData, setIncomeData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // =========================
  // Load Dashboard Data
  // =========================
  const loadDashboard = async () => {
    try {
      setLoading(true);
      setError("");
      const data = await getIncome();
      if (!Array.isArray(data)) throw new Error("Invalid data format");
      setIncomeData(data);
    } catch (err) {
      console.error("Dashboard load error:", err);
      setError(err.message || "Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadDashboard();
  }, []);

  // =========================
  // Real-Time Calculations
  // =========================
  const totalIncome = useMemo(
    () => incomeData?.reduce((acc, d) => acc + (d.amount || 0), 0) || 0,
    [incomeData]
  );

  const averageIncome = useMemo(
    () => (incomeData.length ? Math.round(totalIncome / incomeData.length) : 0),
    [incomeData, totalIncome]
  );

  const growthRate = useMemo(() => {
    if (incomeData.length < 2) return 0;
    const last = incomeData[incomeData.length - 1].amount || 0;
    const prev = incomeData[incomeData.length - 2].amount || 0;
    if (prev === 0) return 0;
    return (((last - prev) / prev) * 100).toFixed(1);
  }, [incomeData]);

  const prediction = useMemo(() => {
    if (!incomeData.length) return [];
    const trendFactor = 1 + growthRate / 100 || 1.05;
    return incomeData.map(d => Math.round(d.amount * trendFactor));
  }, [incomeData, growthRate]);

  // =========================
  // Add Income Handler
  // =========================
  const handleAddIncome = async (amount) => {
    try {
      await addIncome(amount);
      loadDashboard();
    } catch (err) {
      alert(err.message || "Failed to add income");
    }
  };

  // =========================
  // Logout Handler
  // =========================
  const handleLogout = () => {
    logoutUser();
    onLogout();
  };

  // =========================
  // Render Section
  // =========================
  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-purple-800 to-pink-700 p-6 animate-fadeIn">
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-4">
          <h1 className="text-5xl font-extrabold text-white tracking-tight drop-shadow-lg">
            APS AI Financial Dashboard
          </h1>
          <button
            onClick={handleLogout}
            className="bg-red-500 hover:bg-red-600 transition transform hover:scale-105 px-6 py-3 rounded-xl text-white font-bold shadow-lg"
          >
            Logout
          </button>
        </div>

        {/* Error Alert */}
        {error && (
          <div className="bg-red-600 text-white p-4 rounded-lg mb-6 shadow-lg">
            ⚠️ {error}
          </div>
        )}

        {/* Income Form */}
        <div className="glass p-6 rounded-2xl shadow-xl backdrop-blur-lg border border-white/20">
          <IncomeForm onAddIncome={handleAddIncome} />
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6 mt-10">
          <DashboardCard
            title="Total Income"
            value={totalIncome}
            icon="💰"
            growth={growthRate}
            color="bg-gradient-to-r from-yellow-400 via-yellow-300 to-yellow-500"
          />
          <DashboardCard
            title="Average Income"
            value={averageIncome}
            icon="📊"
            growth={growthRate}
            color="bg-gradient-to-r from-green-400 via-green-300 to-green-500"
          />
          <DashboardCard
            title="Growth Rate"
            value={growthRate + "%"}
            icon={growthRate >= 0 ? "📈" : "📉"}
            growth={growthRate}
            color={`${
              growthRate >= 0
                ? "bg-gradient-to-r from-teal-400 via-teal-300 to-teal-500"
                : "bg-gradient-to-r from-red-400 via-red-300 to-red-500"
            }`}
          />
        </div>

        {/* AI Prediction Section */}
        <div className="mt-12 glass p-6 rounded-2xl border border-yellow-400 shadow-2xl backdrop-blur-lg animate-fadeIn">
          <h3 className="text-3xl font-semibold text-yellow-300 mb-4">
            AI Trend Prediction
          </h3>
          <p className="text-white mb-4">
            Next cycle projected values based on current growth trend:
          </p>
          <div className="flex flex-wrap gap-3">
            {prediction.map((val, idx) => (
              <div
                key={idx}
                className="px-4 py-2 bg-green-500/40 text-white rounded-lg font-mono shadow-md hover:bg-green-500 transition transform hover:scale-105"
              >
                ₹ {val}
              </div>
            ))}
          </div>
        </div>

        {/* Chart Section */}
        <div className="mt-12 glass p-6 rounded-2xl shadow-2xl backdrop-blur-lg border border-yellow-300">
          <h3 className="text-3xl font-semibold mb-4 text-gray-100">Income Analytics</h3>
          <IncomeChart data={incomeData.map(d => d.amount)} prediction={prediction} />
        </div>

        {/* Loading */}
        {loading && (
          <div className="text-white mt-6 text-center text-xl animate-pulse">
            🔄 Loading dashboard data...
          </div>
        )}

        {/* Footer */}
        <footer className="mt-16 text-center text-white/70 text-sm">
          © 2026 APS AI | All Rights Reserved
        </footer>
      </div>
    </div>
  );
}
